-- ----------------------------
-- Table structure for server_house
-- ----------------------------
CREATE TABLE `server_house` (
  `house_id` int(10) unsigned NOT NULL DEFAULT '0',
  `house_name` varchar(45) NOT NULL DEFAULT '',
  `house_area` int(10) unsigned NOT NULL DEFAULT '0',
  `location` varchar(45) NOT NULL DEFAULT '',
  `keeper_id` int(10) unsigned NOT NULL DEFAULT '0',
  `is_on_sale` int(10) unsigned NOT NULL DEFAULT '0',
  `is_purchase_basement` int(10) unsigned NOT NULL DEFAULT '0',
  `tax_deadline` datetime NOT NULL,
  `locx1` int(10) NOT NULL DEFAULT '0' COMMENT '座标x1',
  `locx2` int(10) NOT NULL DEFAULT '0' COMMENT '座标x2',
  `locy1` int(10) NOT NULL DEFAULT '0' COMMENT '座标y1',
  `locy2` int(10) NOT NULL DEFAULT '0' COMMENT '座标y2',
  `locx3` int(10) NOT NULL DEFAULT '0' COMMENT '座标x3(用于不规则型小屋第2座标)',
  `locx4` int(10) NOT NULL DEFAULT '0' COMMENT '座标x4(用于不规则型小屋第2座标)',
  `locy3` int(10) NOT NULL DEFAULT '0' COMMENT '座标y3(用于不规则型小屋第2座标)',
  `locy4` int(10) NOT NULL DEFAULT '0' COMMENT '座标y4(用于不规则型小屋第2座标)',
  `mapid` int(10) NOT NULL DEFAULT '0' COMMENT '小屋地图编号',
  `basement` int(10) NOT NULL DEFAULT '0' COMMENT '地下盟屋地图编号',
  `homelocx` int(10) NOT NULL,
  `homelocy` int(10) NOT NULL,
  PRIMARY KEY (`house_id`),
  KEY `house_id` (`house_id`)
) ENGINE=MyISAM DEFAULT CHARSET=utf8;

